130→function println(message = '', color?: Color): void {
131→  const ts = new Date().toISOString().replace('T', ' ').slice(0, 19);
132→  print(`[${ts}] ${message}\n`, color);
133→}
134→
135→function syslog(message = '', color?: Color): void {
136→  println(`‣ ${message}`, color);
137→}
