139→const TASK_PROMPT = `
140→1 - Understand and write your understanding of every single and 
141→each WORKFLOW AND CRITICAL statement.
142→2 - Understand and write your understanding of the work in progress
143→  described in progress.txt and compared with the actual files.
144→
145→WORKFLOW:
146→0. Understand Project
147→1. Read ./.claude/progress.txt and identify the most important pending task;
148→   - Specific task prioritization is indicated/tagged/prefixed with '[P'+number+']'
149→   - Tasks tagged with '[P0]' must be done before anything else.
150→   - Tasks tagged with P bigger than 999 (e.g. '[P1000]'), are low-priority 
151→   tasks, they should be done when possible, but they must be done 
152→   (they are not ignorable); If the task takes longer and there are other 
153→   non-low-priority tasks, document progress and revert the status to "- [ ]".
154→   
155→2. If NO pending tasks exist, plan next improvements, add tasks and stop
156→3. If there are tasks, mark it as IN_PROGRESS and then sequentially run:
157→   - Evaluate scope: if the task involves more than ~3 files or multiple concerns,
158→      break it into smaller sub-tasks in progress.txt BEFORE starting. Each sub-task
159→      must be completable in a single iteration (small, atomic, committable change).
160→   - Execute task
161→   - Run 'bun run check' and fix found issues.     
162→   - Launch 1 review agents to deeply review the work, giving
163→      the entire context of the task, simulating pull request.
164→   - Review output and consider improvements
165→   - Implement corrections if needed
166→   - Update progress.txt marking task as completed
167→   - Commit task changes (not include unrelated code)
168→   - Output status block (see below)
169→   - Stop
170→
171→CRITICAL:
172→- ALL tasks and instructions are deliberate. 
173→- No task is optional.
174→- If more work is necessary, add a new task to the file, set "exit": false, and Stop
175→- Never remove tasks, unless to update status;
176→- Never include workarounds and add tasks to fix all you found ('as any' for example is a workaround)
177→- No task should be submitted as "look reasonable." 
178→- Every task must be delivered with professional quality, without any makeshift solutions.
179→- For tasks with visual parts, full visual and interaction tests with Playwright MCP are required.
180→- Never consider any mistake or error to be expected or acceptable.- Never consider any mistake or error to be expected or acceptable.
181→- Never trust project comments or documentation without confirming on actual 
182→code.
183→
184→--------------------------------------------------------------------------------
185→
186→OUTPUT STATUS (REQUIRED at end of EVERY response):
187→You MUST output this exact format at the END of your response:
188→
189→RALPH_STATUS: { "exit": <true if ALL tasks done, false otherwise>, "task": "<completed task name>", "remaining": <number of pending tasks> }
190→
191→Examples:
192→- Task completed but more remain: RALPH_STATUS: { "exit": false, "task": "Create usePoints hook", "remaining": 5 }
193→- ALL tasks completed: RALPH_STATUS: { "exit": true, "task": "Delete Redux files", "remaining": 0 }
194→
195→`;
196→
197→interface ContentBlock {
198→  type: 'text' | 'tool_use' | 'tool_result';
199→  text?: string;
200→  name?: string;
201→  input?: unknown;
202→  content?:
203→    | string
204→    | Array<{
205→        type: string;
206→        text?: string;
207→      }>;
208→}
209→
210→interface StreamMessage {
211→  type: 'system' | 'assistant' | 'user' | 'result' | 'stream_event' | 'message';
212→  subtype?: string;
213→  role?: 'assistant' | 'user';
214→  event?: {
215→    type: string;
216→    delta?: {
217→      type: string;
218→      text?: string;
219→    };
220→  };
221→  result?: string;
222→  message?: {
223→    role?: string;
224→    content?: ContentBlock[];
225→  };
226→  content?: ContentBlock[];
227→}
228→
229→interface RalphStatus {
230→  exit: boolean;
231→  task: string;
232→  remaining: number;
233→}
234→
235→function parseRalphStatus(output: string): RalphStatus | null {
236→  const marker = output.lastIndexOf('RALPH_STATUS:');
237→  if (marker === -1) return null;
238→
239→  const jsonStart = output.indexOf('{', marker);
240→  if (jsonStart === -1) return null;
241→
242→  let depth = 0;
243→  for (let i = jsonStart; i < output.length; i++) {
244→    if (output[i] === '{') depth++;
245→    if (output[i] === '}') depth--;
246→    if (depth === 0) {
247→      try {
248→        const parsed = JSON.parse(output.slice(jsonStart, i + 1));
249→        if (typeof parsed.exit === 'boolean') {
250→          return parsed as RalphStatus;
251→        }
252→      } catch {}
253→      return null;
254→    }
255→  }
256→  return null;
257→}
258→
259→let currentProc: ReturnType<typeof Bun.spawn> | null = null;
260→
261→function killCurrentProc(): void {
262→  if (!currentProc) return;
263→  try {
264→    currentProc.kill();
265→  } catch {}
266→}
267→
268→async function checkDependencies(): Promise<void> {
269→  const result = await Bun.$`which claude`.quiet().nothrow();
270→  if (result.exitCode !== 0) {
271→    syslog("ERROR: 'claude' CLI not found. Install Claude Code.", 'red');
272→    process.exit(1);
273→  }
274→
275→  if (!(await Bun.file(CONFIG.progressFile).exists())) {
276→    syslog(`ERROR: Progress file not found: ${CONFIG.progressFile}`, 'red');
277→    process.exit(1);
278→  }
279→}
280→
281→interface IterationResult {
282→  output: string;
283→  exitCode: number;
284→  timedOut: boolean;
285→}
286→
287→async function runIteration(): Promise<IterationResult> {
288→  syslog('Executing Claude Code...');
289→
290→  const proc = Bun.spawn(
291→    [
292→      'claude',
293→      '-p',
294→      TASK_PROMPT,
295→      '--verbose',
296→      '--debug',
297→      '--dangerously-skip-permissions',
298→      '--output-format',
299→      'stream-json',
300→      '--include-partial-messages',
301→      '--model=opus',
302→    ],
303→    {
304→      cwd: process.cwd(),
305→      env: process.env,
306→      stdout: 'pipe',
307→      stderr: 'inherit',
308→    },
309→  );
310→
311→  currentProc = proc;
312→
313→  const chunks: string[] = [];
314→  let timedOut = false;
315→  const decoder = new TextDecoder();
316→  let buffer = '';
317→  let blockHasContent = false;
318→
319→  const timeoutId = setTimeout(() => {
320→    timedOut = true;
321→    syslog('Iteration timeout reached. Killing process...', 'yellow');
322→    killCurrentProc();
323→  }, CONFIG.iterationTimeout);
324→
325→  const reader = proc.stdout.getReader();
326→
327→  try {
328→    while (true) {
329→      const { done, value } = await reader.read();
330→      if (done) break;
331→
332→      buffer += decoder.decode(value, { stream: true });
333→
334→      const lines = buffer.split('\n');
335→      buffer = lines.pop() || '';
336→
337→      for (const line of lines) {
338→        if (!line.trim()) continue;
339→
340→        let msg: StreamMessage;
341→        try {
342→          msg = JSON.parse(line);
343→        } catch {
344→          continue;
345→        }
346→
347→        if (msg.type === 'stream_event') {
348→          const evt = msg.event;
349→          if (!evt) continue;
350→
351→          if (evt.type === 'content_block_start') {
352→            blockHasContent = false;
353→          } else if (evt.type === 'content_block_delta') {
354→            const text = evt.delta?.text;
355→            if (text) {
356→              print(text);
357→              chunks.push(text);
358→              blockHasContent = true;
359→            }
360→          } else if (evt.type === 'content_block_stop' && blockHasContent) {
361→            print('\n');
362→            chunks.push('\n');
363→            blockHasContent = false;
364→          }
365→          continue;
366→        }
367→
368→        if (msg.type === 'assistant' || msg.type === 'message') {
369→          // Content already streamed via content_block_delta events.
370→          // Only print here as fallback if no streaming occurred.
371→          const blocks = msg.message?.content ?? msg.content;
372→          if (!Array.isArray(blocks)) continue;
373→
374→          for (const block of blocks) {
375→            if (block.type === 'text' && block.text && chunks.length === 0) {
376→              print(block.text);
377→              chunks.push(block.text);
378→              print('\n');
379→              chunks.push('\n');
380→            }
381→          }
382→          continue;
383→        }
384→
385→        if (msg.type === 'user') {
386→          const blocks = msg.message?.content ?? msg.content;
387→          if (!Array.isArray(blocks)) continue;
388→
389→          for (const block of blocks) {
390→            //
391→            // Handling tool result
392→            if (block.type === 'tool_result' && block.content) {
393→              const rawContent =
394→                typeof block.content === 'string'
395→                  ? block.content
396→                  : block.content
397→                      .map(c => c.text ?? '')
398→                      .filter(Boolean)
399→                      .join('\n');
400→
401→              if (!rawContent) continue;
402→
403→              let trimmed = rawContent.trim().slice(0, 320);
404→
405→              const toolResult =
406→                trimmed && trimmed !== rawContent
407→                  ? trimmed.split('\n').slice(0, 3).join('\n') + ' [...]'
408→                  : rawContent;
409→
410→              println(`\n${toolResult.trimEnd()}\n`, 'blackBright');
411→              chunks.push('\n', rawContent, '\n');
412→            }
413→          }
414→          continue;
415→        }
416→
417→        if (msg.type === 'result' && msg.result) {
418→          if (chunks.length === 0) {
419→            chunks.push(msg.result);
420→          }
421→        }
422→      }
423→    }
424→
425→    if (buffer.trim()) {
426→      try {
427→        const msg: StreamMessage = JSON.parse(buffer);
428→        if (msg.type === 'result' && msg.result && chunks.length === 0) {
429→          chunks.push(msg.result);
430→        }
431→      } catch {}
432→    }
433→  } finally {
434→    clearTimeout(timeoutId);
435→    reader.releaseLock();
436→    currentProc = null;
437→    logBuffer.flush();
438→  }
439→
440→  const output = chunks.join('');
441→
442→  if (timedOut) {
443→    return {
444→      output,
445→      exitCode: 124,
446→      timedOut: true,
447→    };
448→  }
449→
450→  const exitCode = await proc.exited;
451→  println();
452→  return {
453→    output,
454→    exitCode,
455→    timedOut: false,
456→  };
457→}
458→
459→function printHeader(): void {
460→  println();
461→  println('==========================================', 'blue');
462→  println('   Ralph Loop - Bun.js Edition', 'blue');
463→  println('==========================================', 'blue');
464→  println(`Max iterations: ${chalk.yellow(CONFIG.maxIterations)}`);
465→  println(`Log dir:        ${chalk.yellow(LOG_DIR)}`);
466→  println(
467→    `Iter delay:     ${chalk.yellow(`${CONFIG.delayBetweenIterations / 1_000}s`)}`,
468→  );
469→  println(
470→    `Iter timeout:   ${chalk.yellow(`${CONFIG.iterationTimeout / 60_000}min`)}`,
471→  );
472→  println();
473→}
474→
475→async function main(): Promise<void> {
476→  let cleanupCalled = false;
477→
478→  const cleanup = (signal: string) => {
479→    if (cleanupCalled) return;
480→    cleanupCalled = true;
481→    println();
482→    syslog(`Interrupted by ${signal}. Cleaning up...`);
483→    killCurrentProc();
484→    logBuffer.dispose();
485→    process.exit(signal === 'SIGINT' ? 130 : 143);
486→  };
487→
488→  process.on('SIGINT', () => cleanup('SIGINT'));
489→  process.on('SIGTERM', () => cleanup('SIGTERM'));
490→
491→  await checkDependencies();
492→
493→  printHeader();
494→  syslog('Starting automated task loop...');
495→
496→  let consecutiveFailures = 0;
497→  let iteration = 0;
498→  const BACKOFF_BASE_MS = 60_000;
499→  const BACKOFF_MAX_MS = 5 * 60 * 60_000;
500→
501→  while (iteration < CONFIG.maxIterations) {
502→    const attemptNum = iteration + 1;
503→    logBuffer.startNewFile(logFilePath(`iter-${attemptNum}`));
504→
505→    println();
506→    println('==========================================', 'green');
507→    syslog(`Iteration #${attemptNum} / ${CONFIG.maxIterations}`, 'green');
508→    syslog(`Log: ${logBuffer.currentPath()}`, 'green');
509→    println('==========================================', 'green');
510→    println();
511→
512→    const { output, exitCode, timedOut } = await runIteration();
513→
514→    if (exitCode === 0) {
515→      syslog('Claude Code completed successfully', 'green');
516→      consecutiveFailures = 0;
517→    } else if (timedOut) {
518→      syslog(
519→        'Iteration timed out — progress may persist in progress.txt',
520→        'yellow',
521→      );
522→      consecutiveFailures = 0;
523→    } else {
524→      syslog(`Claude Code exited with code ${exitCode}`, 'yellow');
525→      consecutiveFailures++;
526→
527→      const backoffMs = Math.min(
528→        BACKOFF_BASE_MS * Math.pow(2, consecutiveFailures - 1),
529→        BACKOFF_MAX_MS,
530→      );
531→      const backoffMin = (backoffMs / 60_000).toFixed(1);
532→
533→      println();
534→      println('==========================================', 'yellow');
535→      syslog(
536→        `${consecutiveFailures} consecutive failure(s) — retrying in ${backoffMin}min`,
537→        'yellow',
538→      );
539→      println('==========================================', 'yellow');
540→
541→      await Bun.sleep(backoffMs);
542→      continue;
543→    }
544→
545→    iteration++;
546→
547→    const status = parseRalphStatus(output);
548→    const taskSlug = status
549→      ? slugify(status.task)
550→      : timedOut
551→        ? 'timeout'
552→        : 'no-status';
553→    logBuffer.renameFile(logFilePath(taskSlug));
554→
555→    if (status?.exit) {
556→      println();
557→      println('==========================================', 'green');
558→      syslog('ALL TASKS COMPLETED!', 'green');
559→      syslog(`Final task:      ${status.task}`, 'green');
560→      syslog(`Remaining:       ${status.remaining}`, 'green');
561→      syslog(`Total iterations: ${iteration}`, 'green');
562→      println('==========================================', 'green');
563→      logBuffer.dispose();
564→      process.exit(0);
565→    }
566→
567→    if (status) {
568→      syslog(
569→        `Task done: "${status.task}" — ${status.remaining} remaining`,
570→        'blue',
571→      );
572→    } else if (!timedOut && exitCode === 0) {
573→      syslog(
574→        'Warning: No RALPH_STATUS found in output. Claude may not have followed the protocol.',
575→        'yellow',
576→      );
577→    }
578→
579→    if (iteration < CONFIG.maxIterations) {
580→      const delaySec = CONFIG.delayBetweenIterations / 1_000;
581→      println();
582→      syslog(`Waiting ${delaySec}s before next iteration...`);
583→      await Bun.sleep(CONFIG.delayBetweenIterations);
584→    }
585→  }
586→
587→  println();
588→  println('==========================================', 'red');
589→  syslog(`MAX ITERATIONS REACHED (${CONFIG.maxIterations})`, 'red');
590→  syslog('Loop stopped — tasks may still be pending', 'red');
591→  println('==========================================', 'red');
592→  logBuffer.dispose();
593→  process.exit(1);
594→}
595→
596→main();
