281→interface IterationResult {
282→  output: string;
283→  exitCode: number;
284→  timedOut: boolean;
285→}
286→
287→async function runIteration(): Promise<IterationResult> {
288→  syslog('Executing Claude Code...');
289→
290→  const proc = Bun.spawn(
291→    [
292→      'claude',
293→      '-p',
294→      TASK_PROMPT,
295→      '--verbose',
296→      '--debug',
297→      '--dangerously-skip-permissions',
298→      '--output-format',
299→      'stream-json',
300→      '--include-partial-messages',
301→      '--model=opus',
302→    ],
303→    {
304→      cwd: process.cwd(),
305→      env: process.env,
306→      stdout: 'pipe',
307→      stderr: 'inherit',
308→    },
309→  );
310→
311→  currentProc = proc;
312→
313→  const chunks: string[] = [];
314→  let timedOut = false;
315→  const decoder = new TextDecoder();
316→  let buffer = '';
317→  let blockHasContent = false;
318→
319→  const timeoutId = setTimeout(() => {
320→    timedOut = true;
321→    syslog('Iteration timeout reached. Killing process...', 'yellow');
322→    killCurrentProc();
323→  }, CONFIG.iterationTimeout);
324→
325→  const reader = proc.stdout.getReader();
326→
327→  try {
328→    while (true) {
329→      const { done, value } = await reader.read();
330→      if (done) break;
331→
332→      buffer += decoder.decode(value, { stream: true });
333→
334→      const lines = buffer.split('\n');
335→      buffer = lines.pop() || '';
336→
337→      for (const line of lines) {
338→        if (!line.trim()) continue;
339→
340→        let msg: StreamMessage;
341→        try {
342→          msg = JSON.parse(line);
343→        } catch {
344→          continue;
345→        }
346→
347→        if (msg.type === 'stream_event') {
348→          const evt = msg.event;
349→          if (!evt) continue;
350→
351→          if (evt.type === 'content_block_start') {
352→            blockHasContent = false;
353→          } else if (evt.type === 'content_block_delta') {
354→            const text = evt.delta?.text;
355→            if (text) {
356→              print(text);
357→              chunks.push(text);
358→              blockHasContent = true;
359→            }
360→          } else if (evt.type === 'content_block_stop' && blockHasContent) {
361→            print('\n');
362→            chunks.push('\n');
363→            blockHasContent = false;
364→          }
365→          continue;
366→        }
367→
368→        if (msg.type === 'assistant' || msg.type === 'message') {
369→          // Content already streamed via content_block_delta events.
370→          // Only print here as fallback if no streaming occurred.
371→          const blocks = msg.message?.content ?? msg.content;
372→          if (!Array.isArray(blocks)) continue;
373→
374→          for (const block of blocks) {
375→            if (block.type === 'text' && block.text && chunks.length === 0) {
376→              print(block.text);
377→              chunks.push(block.text);
378→              print('\n');
379→              chunks.push('\n');
380→            }
381→          }
382→          continue;
383→        }
384→
385→        if (msg.type === 'user') {
386→          const blocks = msg.message?.content ?? msg.content;
387→          if (!Array.isArray(blocks)) continue;
388→
389→          for (const block of blocks) {
390→            //
391→            // Handling tool result
392→            if (block.type === 'tool_result' && block.content) {
393→              const rawContent =
394→                typeof block.content === 'string'
395→                  ? block.content
396→                  : block.content
397→                      .map(c => c.text ?? '')
398→                      .filter(Boolean)
399→                      .join('\n');
400→
401→              if (!rawContent) continue;
402→
403→              let trimmed = rawContent.trim().slice(0, 320);
404→
405→              const toolResult =
406→                trimmed && trimmed !== rawContent
407→                  ? trimmed.split('\n').slice(0, 3).join('\n') + ' [...]'
408→                  : rawContent;
409→
410→              println(`\n${toolResult.trimEnd()}\n`, 'blackBright');
411→              chunks.push('\n', rawContent, '\n');
412→            }
413→          }
414→          continue;
415→        }
416→
417→        if (msg.type === 'result' && msg.result) {
418→          if (chunks.length === 0) {
419→            chunks.push(msg.result);
420→          }
421→        }
422→      }
423→    }
424→
425→    if (buffer.trim()) {
426→      try {
427→        const msg: StreamMessage = JSON.parse(buffer);
428→        if (msg.type === 'result' && msg.result && chunks.length === 0) {
429→          chunks.push(msg.result);
430→        }
431→      } catch {}
432→    }
433→  } finally {
434→    clearTimeout(timeoutId);
435→    reader.releaseLock();
436→    currentProc = null;
437→    logBuffer.flush();
438→  }
439→
440→  const output = chunks.join('');
441→
442→  if (timedOut) {
443→    return {
444→      output,
445→      exitCode: 124,
446→      timedOut: true,
447→    };
448→  }
449→
450→  const exitCode = await proc.exited;
451→  println();
452→  return {
453→    output,
454→    exitCode,
455→    timedOut: false,
456→  };
457→}
