 50→interface IterationContext {
 51→  iteration: number;
 52→  maxIterations: number;
 53→  logPath: string;
 54→}
 55→
 56→interface FailureContext extends IterationContext {
 57→  exitCode: number;
 58→  consecutiveFailures: number;
 59→}
 60→
 61→interface BackoffContext extends FailureContext {
 62→  backoffMs: number;
