336→interface IterationResult {
337→  output: string;
338→  exitCode: number;
339→  timedOut: boolean;
340→}
341→
342→async function runIteration(): Promise<IterationResult> {
343→  syslog('Executing Claude Code...');
344→
345→  const proc = Bun.spawn(
346→    [
347→      'claude',
348→      '-p',
349→      TASK_PROMPT,
350→      '--verbose',
351→      '--debug',
352→      '--dangerously-skip-permissions',
353→      '--output-format',
354→      'stream-json',
355→      '--include-partial-messages',
356→      '--model=opus',
357→    ],
358→    {
359→      cwd: process.cwd(),
360→      env: process.env,
361→      stdout: 'pipe',
362→      stderr: 'inherit',
363→    },
364→  );
365→
366→  currentProc = proc;
367→
368→  const chunks: string[] = [];
369→  let timedOut = false;
370→  const decoder = new TextDecoder();
371→  let buffer = '';
372→  let blockHasContent = false;
373→
374→  const timeoutId = setTimeout(() => {
375→    timedOut = true;
376→    syslog('Iteration timeout reached. Killing process...', 'yellow');
377→    killCurrentProc();
378→  }, CONFIG.iterationTimeout);
379→
380→  const reader = proc.stdout.getReader();
381→
382→  try {
383→    while (true) {
384→      const { done, value } = await reader.read();
385→      if (done) break;
386→
387→      buffer += decoder.decode(value, { stream: true });
388→
389→      const lines = buffer.split('\n');
390→      buffer = lines.pop() || '';
391→
392→      for (const line of lines) {
393→        if (!line.trim()) continue;
394→
395→        let msg: StreamMessage;
396→        try {
397→          msg = JSON.parse(line);
398→        } catch {
399→          continue;
400→        }
401→
402→        if (msg.type === 'stream_event') {
403→          const evt = msg.event;
404→          if (!evt) continue;
405→
406→          if (evt.type === 'content_block_start') {
407→            blockHasContent = false;
408→          } else if (evt.type === 'content_block_delta') {
409→            const text = evt.delta?.text;
410→            if (text) {
411→              print(text);
412→              chunks.push(text);
413→              blockHasContent = true;
414→            }
415→          } else if (evt.type === 'content_block_stop' && blockHasContent) {
416→            print('\n');
417→            chunks.push('\n');
418→            blockHasContent = false;
419→          }
420→          continue;
421→        }
422→
423→        if (msg.type === 'assistant' || msg.type === 'message') {
424→          // Content already streamed via content_block_delta events.
425→          // Only print here as fallback if no streaming occurred.
426→          const blocks = msg.message?.content ?? msg.content;
427→          if (!Array.isArray(blocks)) continue;
428→
429→          for (const block of blocks) {
430→            if (block.type === 'text' && block.text && chunks.length === 0) {
431→              print(block.text);
432→              chunks.push(block.text);
433→              print('\n');
434→              chunks.push('\n');
435→            }
436→          }
437→          continue;
438→        }
439→
440→        if (msg.type === 'user') {
441→          const blocks = msg.message?.content ?? msg.content;
442→          if (!Array.isArray(blocks)) continue;
443→
444→          for (const block of blocks) {
445→            //
446→            // Handling tool result
447→            if (block.type === 'tool_result' && block.content) {
448→              const rawContent =
449→                typeof block.content === 'string'
450→                  ? block.content
451→                  : block.content
452→                      .map(c => c.text ?? '')
453→                      .filter(Boolean)
454→                      .join('\n');
455→
456→              if (!rawContent) continue;
457→
458→              let trimmed = rawContent.trim().slice(0, 320);
459→
460→              const toolResult =
461→                trimmed && trimmed !== rawContent
462→                  ? trimmed.split('\n').slice(0, 3).join('\n') + ' [...]'
463→                  : rawContent;
464→
465→              println(`\n${toolResult.trimEnd()}\n`, 'blackBright');
466→              chunks.push('\n', rawContent, '\n');
467→            }
468→          }
469→          continue;
470→        }
471→
472→        if (msg.type === 'result' && msg.result) {
473→          if (chunks.length === 0) {
474→            chunks.push(msg.result);
475→          }
476→        }
477→      }
478→    }
479→
480→    if (buffer.trim()) {
481→      try {
482→        const msg: StreamMessage = JSON.parse(buffer);
483→        if (msg.type === 'result' && msg.result && chunks.length === 0) {
484→          chunks.push(msg.result);
485→        }
486→      } catch {}
487→    }
488→  } finally {
489→    clearTimeout(timeoutId);
490→    reader.releaseLock();
491→    currentProc = null;
492→    logBuffer.flush();
493→  }
494→
495→  const output = chunks.join('');
496→
497→  if (timedOut) {
498→    return {
499→      output,
500→      exitCode: 124,
501→      timedOut: true,
502→    };
503→  }
504→
505→  const exitCode = await proc.exited;
506→  println();
507→  return {
508→    output,
509→    exitCode,
510→    timedOut: false,
511→  };
512→}
