530→async function main(): Promise<void> {
531→  let cleanupCalled = false;
532→
533→  const cleanup = (signal: string) => {
534→    if (cleanupCalled) return;
535→    cleanupCalled = true;
536→    hooks.cleanup.call(signal);
537→    println();
538→    syslog(`Interrupted by ${signal}. Cleaning up...`);
539→    killCurrentProc();
540→    logBuffer.dispose();
541→    process.exit(signal === 'SIGINT' ? 130 : 143);
542→  };
543→
544→  process.on('SIGINT', () => cleanup('SIGINT'));
545→  process.on('SIGTERM', () => cleanup('SIGTERM'));
546→
547→  await checkDependencies();
548→
549→  printHeader();
550→  syslog('Starting automated task loop...');
551→
552→  await hooks.loopStart.promise(CONFIG);
553→
554→  let consecutiveFailures = 0;
555→  let iteration = 0;
556→  const BACKOFF_BASE_MS = 60_000;
557→  const BACKOFF_MAX_MS = 5 * 60 * 60_000;
558→
559→  while (iteration < CONFIG.maxIterations) {
560→    const attemptNum = iteration + 1;
561→    logBuffer.startNewFile(logFilePath(`iter-${attemptNum}`));
562→
563→    const iterCtx: IterationContext = {
564→      iteration: attemptNum,
565→      maxIterations: CONFIG.maxIterations,
566→      logPath: logBuffer.currentPath(),
567→    };
568→
569→    println();
570→    println('==========================================', 'green');
571→    syslog(`Iteration #${attemptNum} / ${CONFIG.maxIterations}`, 'green');
572→    syslog(`Log: ${logBuffer.currentPath()}`, 'green');
573→    println('==========================================', 'green');
574→    println();
575→
576→    await hooks.iterationStart.promise(iterCtx);
577→
578→    const result = await runIteration();
579→    const { output, exitCode, timedOut } = result;
580→
581→    if (exitCode === 0) {
582→      syslog('Claude Code completed successfully', 'green');
583→      consecutiveFailures = 0;
584→      await hooks.iterationSuccess.promise(result, iterCtx);
585→    } else if (timedOut) {
586→      syslog(
587→        'Iteration timed out — progress may persist in progress.txt',
588→        'yellow',
589→      );
590→      consecutiveFailures = 0;
591→      hooks.iterationTimeout.call(result, iterCtx);
592→    } else {
593→      syslog(`Claude Code exited with code ${exitCode}`, 'yellow');
594→      consecutiveFailures++;
595→
596→      const failCtx: FailureContext = {
597→        ...iterCtx,
598→        exitCode,
599→        consecutiveFailures,
600→      };
601→      await hooks.iterationFailure.promise(result, failCtx);
602→
603→      const backoffMs = Math.min(
604→        BACKOFF_BASE_MS * Math.pow(2, consecutiveFailures - 1),
605→        BACKOFF_MAX_MS,
606→      );
607→      const backoffMin = (backoffMs / 60_000).toFixed(1);
608→
609→      const backoffCtx: BackoffContext = { ...failCtx, backoffMs };
610→      const skipBackoff = hooks.backoff.call(backoffCtx);
611→
612→      if (skipBackoff) {
613→        syslog('Backoff skipped by hook', 'yellow');
614→      } else {
615→        println();
616→        println('==========================================', 'yellow');
617→        syslog(
618→          `${consecutiveFailures} consecutive failure(s) — retrying in ${backoffMin}min`,
619→          'yellow',
620→        );
621→        println('==========================================', 'yellow');
622→        await Bun.sleep(backoffMs);
623→      }
624→      continue;
625→    }
626→
627→    iteration++;
628→
629→    const rawStatus = parseRalphStatus(output);
630→    const status = hooks.statusParsed.call(rawStatus, output);
631→    const taskSlug = status
632→      ? slugify(status.task)
633→      : timedOut
634→        ? 'timeout'
635→        : 'no-status';
636→    logBuffer.renameFile(logFilePath(taskSlug));
637→
638→    if (status?.exit) {
639→      await hooks.allTasksComplete.promise(status, iteration);
640→      println();
641→      println('==========================================', 'green');
642→      syslog('ALL TASKS COMPLETED!', 'green');
643→      syslog(`Final task:      ${status.task}`, 'green');
644→      syslog(`Remaining:       ${status.remaining}`, 'green');
645→      syslog(`Total iterations: ${iteration}`, 'green');
646→      println('==========================================', 'green');
647→      logBuffer.dispose();
648→      process.exit(0);
649→    }
650→
651→    if (status) {
652→      await hooks.taskComplete.promise(status, iterCtx);
653→      syslog(
654→        `Task done: "${status.task}" — ${status.remaining} remaining`,
655→        'blue',
656→      );
657→    } else if (!timedOut && exitCode === 0) {
658→      syslog(
659→        'Warning: No RALPH_STATUS found in output. Claude may not have followed the protocol.',
660→        'yellow',
661→      );
662→    }
663→
664→    if (iteration < CONFIG.maxIterations) {
665→      const delaySec = CONFIG.delayBetweenIterations / 1_000;
666→      println();
667→      syslog(`Waiting ${delaySec}s before next iteration...`);
668→      await Bun.sleep(CONFIG.delayBetweenIterations);
669→    }
670→  }
671→
672→  hooks.loopEnd.call(iteration);
673→
674→  println();
675→  println('==========================================', 'red');
676→  syslog(`MAX ITERATIONS REACHED (${CONFIG.maxIterations})`, 'red');
677→  syslog('Loop stopped — tasks may still be pending', 'red');
678→  println('==========================================', 'red');
679→  logBuffer.dispose();
680→  process.exit(1);
681→}
682→
683→main();
