  allTasksComplete: new AsyncSeriesHook<[RalphStatus, number]>([
    'status',
    'totalIterations',
  ]),
  backoff: new SyncBailHook<[BackoffContext], boolean>(['context']),
  loopEnd: new SyncHook<[number]>(['totalIterations']),
  cleanup: new SyncHook<[string]>(['signal']),
};

