#!/usr/bin/env bun

/**
 * Ralph Loop - Automated Claude Code Task Executor
 *
 * Based on Geoffrey Huntley's Ralph Wiggum technique:
 * - Fresh context per iteration (new Claude instance each time)
 * - Memory persists through files only (git, progress.txt)
 * - One task per iteration
 * - Completion signal terminates loop
 *
 * Uses Claude CLI's --output-format stream-json for real-time streaming.
 *
 * @see https://ghuntley.com/ralph/
 */

import { appendFileSync, mkdirSync, renameSync } from 'node:fs';
import { chalk } from 'zx';
import {
  AsyncSeriesHook,
  SyncHook,
  SyncWaterfallHook,
  SyncBailHook,
} from 'tapable';

const ANSI_REGEX = /\x1B\[[0-9;]*m/g;
const stripAnsi = (s: string): string => s.replace(ANSI_REGEX, '');

function parsePositiveInt(arg: string | undefined, fallback: number): number {
  const parsed = parseInt(arg ?? String(fallback), 10);
  if (isNaN(parsed) || parsed <= 0) {
    console.error(`Error: expected a positive integer, got "${arg}"`);
    process.exit(1);
  }
  return parsed;
}

const LOG_DIR = './.loop';
mkdirSync(LOG_DIR, { recursive: true });

const CONFIG = Object.freeze({
  maxIterations: parsePositiveInt(Bun.argv[2], 100),
  delayBetweenIterations: 1_000,
  progressFile: './.claude/progress.txt',
  iterationTimeout: 600_000,
  logFlushInterval: 2_000,
  exitPattern: /RALPH_STATUS:\s*\{[^}]*"exit":\s*true[^}]*\}/,
});

interface IterationResult {
  output: string;
  exitCode: number;
  timedOut: boolean;
}

interface RalphStatus {
  exit: boolean;
  task: string;
  remaining: number;
}

interface IterationContext {
  iteration: number;
  maxIterations: number;
  logPath: string;
}

interface FailureContext extends IterationContext {
  exitCode: number;
  consecutiveFailures: number;
}

interface BackoffContext extends FailureContext {
  backoffMs: number;
}

/**
 * Tapable hooks for the Ralph Loop lifecycle.
 *
 * Hook contracts:
 * - `resolveStatus` (SyncWaterfallHook): Taps MUST return `RalphStatus | null`.
 *   Only the first argument (status) is waterfalled; the second (output) is read-only context.
 * - `shouldSkipBackoff` (SyncBailHook): Return `true` to skip backoff. Return `undefined`
 *   to defer to the next tap. Do NOT return `false` — it short-circuits without skipping.
 * - `cleanup` (SyncHook): Only synchronous side effects are guaranteed. `process.exit`
 *   follows immediately.
 */
const hooks = {
  loopStart: new AsyncSeriesHook<[typeof CONFIG]>(['config']),
  iterationStart: new AsyncSeriesHook<[IterationContext]>(['context']),
  iterationSuccess: new AsyncSeriesHook<[IterationResult, IterationContext]>([
    'result',
    'context',
  ]),
  iterationTimeout: new AsyncSeriesHook<[IterationResult, IterationContext]>([
    'result',
    'context',
  ]),
  iterationFailure: new AsyncSeriesHook<[IterationResult, FailureContext]>([
    'result',
    'context',
  ]),
  resolveStatus: new SyncWaterfallHook<[RalphStatus | null, string]>([
    'status',
    'output',
  ]),
  taskComplete: new AsyncSeriesHook<[RalphStatus, IterationContext]>([
    'status',
    'context',
  ]),
  allTasksComplete: new AsyncSeriesHook<[RalphStatus, number]>([
    'status',
    'totalIterations',
  ]),
  shouldSkipBackoff: new SyncBailHook<[BackoffContext], boolean | undefined>([
    'context',
  ]),
  loopEnd: new AsyncSeriesHook<[number]>(['totalIterations']),
  cleanup: new SyncHook<[string]>(['signal']),
};

export { hooks as ralphHooks };

function slugify(text: string): string {
  return text
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 60);
}

function logTimestamp(): string {
  const d = new Date();
  return `${d.toISOString().slice(0, 10)}_${d.toISOString().slice(11, 19).replace(/:/g, '')}`;
}

function logFilePath(slug: string): string {
  return `${LOG_DIR}/${logTimestamp()}_${slug}.log`;
}

class LogBuffer {
  private buf: string[] = [];
  private timer: ReturnType<typeof setInterval> | null = null;
  private path: string;

  constructor(
    initialPath: string,
    private readonly flushMs: number,
  ) {
    this.path = initialPath;
    this.timer = setInterval(() => this.flush(), this.flushMs);
    if (this.timer && typeof this.timer === 'object' && 'unref' in this.timer) {
      (this.timer as NodeJS.Timeout).unref();
    }
  }

  write(raw: string): void {
    this.buf.push(stripAnsi(raw));
  }

  flush(): void {
    if (this.buf.length === 0) return;
    const chunk = this.buf.join('');
    this.buf.length = 0;
    try {
      appendFileSync(this.path, chunk);
    } catch (err) {
      console.error(`[LogBuffer] write failed: ${err}`);
    }
  }

  startNewFile(newPath: string): void {
    this.flush();
    this.path = newPath;
  }

  renameFile(newPath: string): void {
    this.flush();
    try {
      renameSync(this.path, newPath);
      this.path = newPath;
    } catch {}
  }

  currentPath(): string {
    return this.path;
  }

  dispose(): void {
    if (this.timer) clearInterval(this.timer);
    this.flush();
  }
}

const logBuffer = new LogBuffer(
  logFilePath('startup'),
  CONFIG.logFlushInterval,
);

type Color = 'green' | 'yellow' | 'red' | 'blue' | 'blackBright';

function print(message: string, color?: Color): void {
  const colored = color ? chalk[color](message) : message;
  process.stdout.write(colored);
  logBuffer.write(message);
}

function println(message = '', color?: Color): void {
  const ts = new Date().toISOString().replace('T', ' ').slice(0, 19);
  print(`[${ts}] ${message}\n`, color);
}

function syslog(message = '', color?: Color): void {
  println(`‣ ${message}`, color);
}

async function callHookSafe<T extends unknown[]>(
  hook: AsyncSeriesHook<T>,
  name: string,
  ...args: T
): Promise<void> {
  try {
    await hook.promise(...args);
  } catch (err) {
    syslog(`Hook "${name}" error: ${err}`, 'red');
  }
}

